{"expression": "// Extract ALL text content from the page recursively
function extractContent(node, depth = 0) {
  let result = [];
  if (node.nodeType === Node.TEXT_NODE) {
    const text = node.textContent.trim();
    if (text) result.push(text);
  } else if (node.nodeType === Node.ELEMENT_NODE) {
    const tag = node.tagName.toLowerCase();
    // Skip scripts, styles, metadata
    if (['script','style','noscript','iframe','svg','path'].includes(tag)) return result;

    // Get heading info
    if (['h1','h2','h3','h4','h5','h6'].includes(tag)) {
      const txt = node.textContent.trim();
      if (txt) result.push(`[${tag}] ${txt}`);
    }

    for (const child of node.childNodes) {
      result = result.concat(extractContent(child, depth + 1));
    }

    // Detect bullets
    if (tag === 'li') {
      const txt = node.textContent.trim();
      if (txt) result.push(`• ${txt}`);
    }
  }
  return result;
}

const allText = extractContent(document.body);
const unique = [...new Set(allText)];
unique;
"}

