import re

class ContentExtractor(HTMLParser):
    def __init__(self):
        super().__init__()
        self.sections = {}
        self.current_section = "header"
        self.current_text = []
        self.skip_tags = {'script', 'style', 'noscript', 'iframe', 'path', 'svg'}
        self.heading_tags = {'h1', 'h2', 'h3', 'h4', 'h5', 'h6'}
        self.in_skip = 0
        self.heading_depth = 0

    def handle_starttag(self, tag, attrs):
        if tag in self.skip_tags:
            self.in_skip += 1
            return
        if tag in self.heading_tags:
            self.heading_depth += 1
            self._flush_text()

    def handle_endtag(self, tag):
        if tag in self.skip_tags and self.in_skip > 0:
            self.in_skip -= 1
            return
        if tag in self.heading_tags:
            self.heading_depth -= 1
            # H2 or H3 marks a new section
            if tag in ('h2', 'h3'):
                self._flush_text()

    def handle_data(self, data):
        if self.in_skip: return
        text = data.strip()
        if text:
            prefix = ""
            if self.heading_depth > 0:
                prefix = "#" * self.heading_depth + " "
            self.current_text.append(prefix + text)

    def _flush_text(self):
        if self.current_text:
            text = '\n'.join(self.current_text)
            if text.strip():
                # Use first line as section key
                key = self.current_text[0].replace('# ', '').replace('## ', '').strip()[:40]
                self.sections[key] = text
            self.current_text = []

    def get_content(self):
        self._flush_text()
        return self.sections

