import { HeroCarousel } from "@/components/hero-carousel"
import { CookieConsent } from "@/components/cookie-consent"
import { CartToastListener } from "@/components/cart-toast-listener"
import { RecentlyViewed } from "@/components/recently-viewed"
import { ExitIntentPopup } from "@/components/exit-intent"
import { NewsletterForm } from "@/components/newsletter-form"
import { NewsletterSuccess } from "@/components/ui"
import { WhatsAppFloat } from "@/components/whatsapp-float"
import content from "@/content/es.json"
import siteConfig from "@/config/site.json"
import { useState } from "react"
import {
  StatsSection,
  NewArrivalsSection,
  FeaturedProductsSection,
  FeaturesSection,
  StoreLocatorSection,
  CategoryGridSection,
  TestimonialsSection,
  PaymentMethodsSection,
  NewsletterSection,
  FinalCtaSection,
} from "@/components/home/home-sections"

const c = content as any
const h = c.home || {}
const allProducts = h.productCatalog?.products || []
const categories = h.productCatalog?.categories || []
const site = siteConfig as any
const ICON_MAP: Record<string, string> = site.homepage?.categoryIcons || {}
const testimonials = h.testimonials || []
const features = h.features?.items || []
const stats = h.stats?.items || []
const storeLocator = c.storeLocator || {}

// Derived arrays from single product list — no duplication
const newArrivals = allProducts
  .filter((p: any) => p.isNew)
  .slice(0, h.newArrivals?.count || 8)
const featuredProducts = allProducts
  .filter((p: any) => p.featured)
  .slice(0, h.featuredProducts?.count || 6)

function HomePage() {
  const [cartOpen, setCartOpen] = useState(false)

  return (
    <>
      <Header onCartClick={() => setCartOpen(true)} />
      <CartToastListener />
      <NewsletterSuccess />
      <PromoCarousel />
      <HeroCarousel />

      <StatsSection stats={stats} />
      <NewArrivalsSection
        newArrivals={newArrivals}
        title={h.newArrivals?.title}
        subtitle={h.newArrivals?.subtitle}
      />
      <FeaturedProductsSection
        products={featuredProducts}
        title={h.featuredProducts?.title}
      />
      <FeaturesSection
        features={features}
        title={h.features?.title}
      />
      <StoreLocatorSection storeLocator={storeLocator} />
      <CategoryGridSection
        categories={categories}
        iconMap={ICON_MAP}
        title={h.productCatalog?.title}
      />
      <TestimonialsSection testimonials={testimonials} />
      <PaymentMethodsSection installmentsText={c.paymentMethods?.installments} />
      <NewsletterSection
        title={h.newsletter?.title}
        description={h.newsletter?.description}
        placeholder={h.newsletter?.placeholder}
        buttonText={h.newsletter?.buttonText}
      />
      <FinalCtaSection finalCta={h.finalCta} />

      <Footer />
      <RecentlyViewed />
      <ExitIntentPopup />
      <WhatsAppFloat
        phone={c.home?.contact?.whatsapp || site.contact?.whatsapp || "[REDACTED_PHONE]"}
        message={c.whatsapp?.defaultMessage || "Hola! Quiero informacion"}
      />
      <CartSidebar open={cartOpen} onClose={() => setCartOpen(false)} />
      <CookieConsent />
    </>
  )
}

export default function Page() {
  return <HomePage />
}
